package com.oms.audit.entity;import javax.persistence.*;import lombok.Data;@Entity@Data@Table(name = "servers")public class ServerInfo {    @Id    @GeneratedValue(strategy = GenerationType.IDENTITY)    private Long id;    private String ip;    @Column(columnDefinition = "int default 22")    private int sshPort = 22;    private String sshUser;    private String sshPassword;    private Long assignedUserId;    @Column(columnDefinition = "bigint default 0")    private long lastLogOffset = 0;    private String status = "OFFLINE"; }